// When a repeating task is marked as done via Task.Update (not via TaskBucket.Update),
// we need to move it to the default bucket after updateDone resets it to undone.
if t.ProjectID == ot.ProjectID && t.isRepeating() && t.Done != ot.Done {
	// For repeating tasks being marked as done from a non-done bucket,
	// the task should end up in the default bucket.
	for _, view := range views {
		currentTaskBucket := &TaskBucket{}
		_, err = s.Where("task_id = ? AND project_view_id = ?", t.ID, view.ID).
			Get(currentTaskBucket)
		if err != nil {
			return err
		}

		if currentTaskBucket.BucketID != view.DefaultBucketID {
			bucketID := view.DefaultBucketID
			if bucketID == 0 {
				bucketID, err = getDefaultBucketID(s, view)
				if err != nil {
					return err
				}
			}

			tb := &TaskBucket{
				BucketID:      bucketID,
				TaskID:        t.ID,
				ProjectViewID: view.ID,
				ProjectID:     t.ProjectID,
			}
			err = updateTaskBucket(s, a, tb)
			if err != nil {
				return err
			}

			tp := TaskPosition{
				TaskID:        t.ID,
				ProjectViewID: view.ID,
				Position:      calculateDefaultPosition(t.Index, t.Position),
			}
			err = updateTaskPosition(s, a, &tp)
			if err != nil {
				return err
			}
		}
	}
